import { useState, useEffect, useRef } from 'react';
import { io } from 'socket.io-client';
import { Search, ThumbsUp, Music, X, Play, Pause, SkipForward, Plus, ChevronDown, Trash2, LogOut, User, Eye, EyeOff, Settings, ArrowLeft, ShieldCheck, UserCircle2, Power, Edit2, Link2, Volume2, VolumeX } from 'lucide-react';

const socket = io({ transports: ['websocket'] });
const LOGO = 'data:image/jpeg;base64,';

function fmtDur(s) {
  if (!s || isNaN(s)) return '0:00';
  return Math.floor(s / 60) + ':' + String(Math.floor(s % 60)).padStart(2, '0');
}

function CoverImg({ id, size = 'md' }) {
  const [err, setErr] = useState(false);
  const cls = size === 'lg' ? 'w-20 h-20' : size === 'sm' ? 'w-10 h-10' : 'w-12 h-12';
  if (!id || err) return (
    <div className={'rounded-xl bg-gray-800 flex items-center justify-center flex-shrink-0 ' + cls}>
      <Music size={size === 'lg' ? 28 : 16} className="text-gray-600" />
    </div>
  );
  return <img src={'/api/cover/' + id} onError={() => setErr(true)}
    className={'rounded-xl object-cover flex-shrink-0 ' + cls} alt="" />;
}

// ── Auth Modal ────────────────────────────────────────────────────────────────
function AuthModal({ onAuth }) {
  const [tab, setTab]             = useState('login');
  const [username, setUsername]   = useState('');
  const [password, setPassword]   = useState('');
  const [password2, setPassword2] = useState('');
  const [showPw, setShowPw]       = useState(false);
  const [showPw2, setShowPw2]     = useState(false);
  const [error, setError]         = useState('');
  const [loading, setLoading]     = useState(false);

  const submit = async () => {
    if (!username.trim() || !password) return setError('Rellena todos los campos');
    if (tab === 'register' && !password2) return setError('Confirma la contrasena');
    if (tab === 'register' && password !== password2) return setError('Las contrasenas no coinciden');
    setError(''); setLoading(true);
    try {
      const url = tab === 'login' ? '/api/auth/login' : '/api/auth/register';
      const r = await fetch(url, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username: username.trim(), password })
      });
      const data = await r.json();
      if (data.token) onAuth(data.token, data.user);
      else setError(data.error || 'Error');
    } catch { setError('Error de conexion'); }
    setLoading(false);
  };
  const handleKey = (e) => { if (e.key === 'Enter') submit(); };

  return (
    <div className="min-h-[100dvh] flex items-center justify-center px-4"
      style={{ background: 'linear-gradient(160deg, #1a0505 0%, #0d0608 100%)' }}>
      <div className="w-full max-w-sm">
        <div className="flex flex-col items-center mb-8">
          <img src={LOGO} className="w-20 h-20 object-contain rounded-full bg-white p-1 mb-4 shadow-xl shadow-red-900/30" alt="Falla" />
          <h1 className="text-3xl font-extrabold tracking-tight">TuriaDJ</h1>
          <p className="text-xs text-red-400 font-semibold uppercase tracking-widest mt-1">Falla Turia · Plaça de l'Ajuntament</p>
        </div>
        <div className="flex bg-gray-900 rounded-2xl p-1 mb-6">
          {['login','register'].map(t => (
            <button key={t} onClick={() => { setTab(t); setError(''); setPassword2(''); }}
              className={'flex-1 py-2.5 rounded-xl text-sm font-semibold transition-all ' +
                (tab === t ? 'bg-red-700 text-white shadow' : 'text-gray-500 hover:text-gray-300')}>
              {t === 'login' ? 'Iniciar sesion' : 'Registrarse'}
            </button>
          ))}
        </div>
        <div className="space-y-3">
          <div className="relative">
            <User size={15} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
            <input value={username} onChange={e => setUsername(e.target.value)} onKeyDown={handleKey}
              placeholder="Nombre de usuario"
              className="w-full bg-gray-900 border border-gray-700 focus:border-red-600/70 rounded-xl pl-10 pr-4 py-3 text-sm focus:outline-none placeholder-gray-600 transition-colors" />
          </div>
          <div className="relative">
            <input type={showPw ? 'text' : 'password'} value={password}
              onChange={e => setPassword(e.target.value)} onKeyDown={handleKey}
              placeholder="Contrasena"
              className="w-full bg-gray-900 border border-gray-700 focus:border-red-600/70 rounded-xl px-4 py-3 pr-10 text-sm focus:outline-none placeholder-gray-600 transition-colors" />
            <button onClick={() => setShowPw(p => !p)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-300">
              {showPw ? <EyeOff size={16} /> : <Eye size={16} />}
            </button>
          </div>
          {tab === 'register' && (
            <div className="relative">
              <input type={showPw2 ? 'text' : 'password'} value={password2}
                onChange={e => setPassword2(e.target.value)} onKeyDown={handleKey}
                placeholder="Repetir contrasena"
                className="w-full bg-gray-900 border border-gray-700 focus:border-red-600/70 rounded-xl px-4 py-3 pr-10 text-sm focus:outline-none placeholder-gray-600 transition-colors" />
              <button onClick={() => setShowPw2(p => !p)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-300">
                {showPw2 ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          )}
          {error && <p className="text-red-400 text-xs text-center">{error}</p>}
          <button onClick={submit} disabled={loading}
            className="w-full py-3.5 rounded-2xl font-bold text-sm transition-all active:scale-[0.98] mt-2"
            style={{ background: loading ? '#7f1d1d' : 'linear-gradient(135deg,#dc2626,#b91c1c)', boxShadow: '0 4px 20px rgba(220,38,38,0.35)' }}>
            {loading ? '...' : (tab === 'login' ? 'Entrar' : 'Crear cuenta')}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Admin Panel ───────────────────────────────────────────────────────────────
function AdminPanel({ currentUser, authToken, onClose }) {
  const [users, setUsers]           = useState([]);
  const [loading, setLoading]       = useState(true);
  const [confirmDelete, setConfirmDelete] = useState(null);
  const [saving, setSaving]         = useState(null);

  const load = async () => {
    setLoading(true);
    try {
      const r = await fetch('/api/admin/users', { headers: { Authorization: 'Bearer ' + authToken } });
      setUsers(await r.json());
    } catch {}
    setLoading(false);
  };

  useEffect(() => { load(); }, []);

  const updateRole = async (id, role) => {
    setSaving(id);
    await fetch('/api/admin/users/' + id, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + authToken },
      body: JSON.stringify({ role })
    });
    setSaving(null);
    load();
  };

  const doDelete = async (id) => {
    await fetch('/api/admin/users/' + id, {
      method: 'DELETE',
      headers: { Authorization: 'Bearer ' + authToken }
    });
    setConfirmDelete(null);
    load();
  };

  const adminCount = users.filter(u => u.role === 'admin').length;

  return (
    <div className="fixed inset-0 z-50 flex flex-col fade-in"
      style={{ background: 'linear-gradient(160deg, #1a0505 0%, #0d0608 100%)' }}>

      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-4 border-b border-gray-800/60">
        <button onClick={onClose}
          className="w-9 h-9 flex items-center justify-center rounded-xl bg-gray-900 text-gray-400 hover:text-white transition-colors">
          <ArrowLeft size={18} />
        </button>
        <div className="flex-1">
          <h2 className="font-bold text-base leading-tight">Panel de control</h2>
          <p className="text-xs text-gray-500">Gestion de usuarios</p>
        </div>
        <div className="text-right">
          <p className="text-xs text-gray-500">{users.length} usuarios</p>
          <p className="text-xs text-yellow-600">{adminCount} admin</p>
        </div>
      </div>

      {/* User list */}
      <div className="flex-1 overflow-y-auto px-4 py-4 max-w-2xl mx-auto w-full">
        {loading ? (
          <div className="flex justify-center py-16">
            <div className="w-7 h-7 border-2 border-red-700 border-t-transparent rounded-full animate-spin" />
          </div>
        ) : (
          <div className="space-y-2">
            {users.map(user => {
              const isSelf    = user.id === currentUser.id;
              const isDeleting = confirmDelete === user.id;
              return (
                <div key={user.id}
                  className={'rounded-2xl border transition-all ' +
                    (isDeleting ? 'border-red-800/60 bg-red-950/30' : 'border-gray-800/40 bg-gray-900/50')}>
                  {isDeleting ? (
                    <div className="flex items-center justify-between px-4 py-3.5 gap-3">
                      <div>
                        <p className="text-sm font-semibold text-red-400">Eliminar usuario</p>
                        <p className="text-xs text-gray-500">Esta accion no se puede deshacer</p>
                      </div>
                      <div className="flex gap-2 flex-shrink-0">
                        <button onClick={() => doDelete(user.id)}
                          className="px-3 py-1.5 bg-red-700 hover:bg-red-600 text-white rounded-xl text-xs font-bold transition-colors">
                          Eliminar
                        </button>
                        <button onClick={() => setConfirmDelete(null)}
                          className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-gray-300 rounded-xl text-xs font-semibold transition-colors">
                          Cancelar
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex items-center gap-3 px-4 py-3.5">
                      {/* Avatar */}
                      <div className={'w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ' +
                        (user.role === 'admin' ? 'bg-yellow-900/40' : 'bg-gray-800')}>
                        {user.role === 'admin'
                          ? <ShieldCheck size={18} className="text-yellow-500" />
                          : <UserCircle2 size={18} className="text-gray-500" />}
                      </div>

                      {/* Info */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <p className="font-semibold text-sm truncate">{user.username}</p>
                          {isSelf && <span className="text-[10px] text-gray-600 font-medium">(tú)</span>}
                          <span className={'text-[10px] font-bold px-1.5 py-0.5 rounded ' +
                            (user.role === 'admin'
                              ? 'bg-yellow-900/50 text-yellow-500'
                              : 'bg-gray-800 text-gray-500')}>
                            {user.role === 'admin' ? 'ADMIN' : 'USUARIO'}
                          </span>
                        </div>
                        <p className="text-xs text-gray-600 mt-0.5">
                          Registrado {new Date(user.created_at).toLocaleDateString('es-ES', { day:'numeric', month:'short', year:'numeric' })}
                        </p>
                      </div>

                      {/* Role selector */}
                      <select
                        value={user.role}
                        onChange={e => updateRole(user.id, e.target.value)}
                        disabled={isSelf || saving === user.id}
                        className={'text-xs px-2 py-1.5 rounded-xl border focus:outline-none transition-colors flex-shrink-0 ' +
                          (isSelf ? 'bg-gray-900 border-gray-800 text-gray-600 cursor-not-allowed opacity-40'
                                  : 'bg-gray-800 border-gray-700 text-white focus:border-red-600 cursor-pointer')}>
                        <option value="user">Usuario</option>
                        <option value="admin">Admin</option>
                      </select>

                      {/* Delete */}
                      <button
                        onClick={() => setConfirmDelete(user.id)}
                        disabled={isSelf}
                        className={'w-8 h-8 flex items-center justify-center rounded-xl transition-all flex-shrink-0 ' +
                          (isSelf ? 'text-gray-800 cursor-not-allowed'
                                  : 'text-gray-600 hover:text-red-500 hover:bg-red-900/20')}>
                        <Trash2 size={15} />
                      </button>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}



// ── Session Panel ─────────────────────────────────────────────────────────────
function SessionPanel({ sessionActive, sessionName: initName, sessionDesc: initDesc, authFetch, onStopAudio, onClose }) {
  const [name, setName]           = useState(initName || '');
  const [desc, setDesc]           = useState(initDesc  || '');
  const [saving, setSaving]       = useState(false);
  const [saved,  setSaved]        = useState(false);
  const [copied, setCopied]       = useState(false);
  const [ending, setEnding]       = useState(false);
  const [endConfirm, setEndConfirm] = useState(false);

  const shareUrl = "https://turiadj.i-automate.es";

  const saveInfo = async () => {
    setSaving(true);
    await authFetch('/api/session/info', { method: 'POST', body: JSON.stringify({ name, desc }) });
    setSaving(false); setSaved(true); setTimeout(() => setSaved(false), 2000);
  };

  const copyLink = () => {
    navigator.clipboard.writeText(shareUrl)
      .then(() => { setCopied(true); setTimeout(() => setCopied(false), 2500); })
      .catch(() => {});
  };

  const handleStart = async () => {
    await authFetch('/api/session/info', { method: 'POST', body: JSON.stringify({ name, desc }) });
    await authFetch('/api/session/start', { method: 'POST' });
    onClose();
  };

  const handleEnd = async () => {
    setEnding(true);
    onStopAudio();
    await authFetch('/api/session/end', { method: 'POST' });
    setEnding(false); onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex flex-col fade-in"
      style={{ background: 'linear-gradient(160deg, #1a0505 0%, #0d0608 100%)' }}>

      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-4 border-b border-gray-800/60">
        <button onClick={onClose}
          className="w-9 h-9 flex items-center justify-center rounded-xl bg-gray-900 text-gray-400 hover:text-white transition-colors">
          <ArrowLeft size={18} />
        </button>
        <div className="flex-1">
          <h2 className="font-bold text-base leading-tight">Editar sesion</h2>
          <p className="text-xs text-gray-500">Configura y comparte la sesion</p>
        </div>
        <span className={'text-[11px] font-bold px-2.5 py-1 rounded-lg ' +
          (sessionActive ? 'bg-green-900/40 text-green-400' : 'bg-gray-800 text-gray-500')}>
          {sessionActive ? '● ACTIVA' : '○ CERRADA'}
        </span>
      </div>

      <div className="flex-1 overflow-y-auto px-4 py-5 max-w-2xl mx-auto w-full space-y-5">

        {/* Name */}
        <div>
          <label className="text-xs text-gray-500 font-semibold uppercase tracking-widest block mb-2">
            Nombre de la sesion
          </label>
          <input
            value={name}
            onChange={e => setName(e.target.value)}
            placeholder="Ej: Sesion Remember, Noche de Falla 2025..."
            className="w-full bg-gray-900/70 border border-gray-700/60 rounded-xl px-4 py-3 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-red-600/60 transition-colors"
          />
        </div>

        {/* Description */}
        <div>
          <label className="text-xs text-gray-500 font-semibold uppercase tracking-widest block mb-2">
            Descripcion
          </label>
          <textarea
            value={desc}
            onChange={e => setDesc(e.target.value)}
            rows={4}
            placeholder="Describe la sesion, el estilo musical, el lugar..."
            className="w-full bg-gray-900/70 border border-gray-700/60 rounded-xl px-4 py-3 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-red-600/60 transition-colors resize-none"
          />
        </div>

        {/* Save */}
        <button onClick={saveInfo} disabled={saving}
          className="w-full py-2.5 bg-gray-800 hover:bg-gray-700 disabled:opacity-50 text-gray-200 rounded-xl text-sm font-semibold transition-colors">
          {saving ? 'Guardando...' : saved ? 'Guardado!' : 'Guardar cambios'}
        </button>

        {/* Share link */}
        <div>
          <label className="text-xs text-gray-500 font-semibold uppercase tracking-widest block mb-2">
            Link para compartir
          </label>
          <div className="flex gap-2">
            <div className="flex-1 flex items-center gap-2 bg-gray-900/70 border border-gray-700/60 rounded-xl px-4 py-3 min-w-0">
              <Link2 size={14} className="text-gray-600 flex-shrink-0" />
              <span className="text-sm text-gray-400 truncate select-all">{shareUrl}</span>
            </div>
            <button onClick={copyLink}
              className={'px-4 rounded-xl text-sm font-semibold transition-all flex-shrink-0 ' +
                (copied ? 'bg-green-800/60 text-green-300' : 'bg-gray-800 hover:bg-gray-700 text-gray-300')}>
              {copied ? 'Copiado!' : 'Copiar'}
            </button>
          </div>
          <p className="text-xs text-gray-700 mt-2">Comparte este enlace en redes o grupos para que otros se unan</p>
        </div>

        {/* Session control */}
        <div className="border-t border-gray-800/50 pt-5">
          <p className="text-xs text-gray-500 font-semibold uppercase tracking-widest mb-3">Control de sesion</p>
          {!sessionActive ? (
            <button onClick={handleStart}
              className="w-full py-3.5 rounded-xl text-white text-sm font-bold transition-all flex items-center justify-center gap-2 active:scale-[0.98]"
              style={{ background: 'linear-gradient(135deg,#16a34a,#15803d)', boxShadow: '0 4px 20px rgba(22,163,74,0.3)' }}>
              <Power size={16} /> Iniciar sesion
            </button>
          ) : !endConfirm ? (
            <button onClick={() => setEndConfirm(true)}
              className="w-full py-3.5 border border-gray-700/60 bg-gray-900/60 hover:border-red-800/60 hover:bg-red-950/30 text-gray-400 hover:text-red-400 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-2">
              <Power size={16} /> Finalizar sesion
            </button>
          ) : (
            <div className="rounded-2xl border border-red-800/50 bg-red-950/30 p-4 space-y-3">
              <p className="text-sm font-semibold text-red-400">Finalizar sesion</p>
              <p className="text-xs text-gray-500">Se detendra la musica y se vaciara la cola.</p>
              <div className="flex gap-2">
                <button onClick={handleEnd} disabled={ending}
                  className="flex-1 py-2.5 bg-red-700 hover:bg-red-600 disabled:opacity-60 text-white rounded-xl text-sm font-bold transition-colors">
                  {ending ? 'Finalizando...' : 'Confirmar'}
                </button>
                <button onClick={() => setEndConfirm(false)}
                  className="flex-1 py-2.5 bg-gray-800 hover:bg-gray-700 text-gray-300 rounded-xl text-sm font-semibold transition-colors">
                  Cancelar
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────────
export default function UnifiedView() {
  const [adminPanelOpen, setAdminPanelOpen] = useState(false);

  // ── auth ───────────────────────────────────────────────────────────────────
  const [authToken, setAuthToken]     = useState(() => localStorage.getItem('jv_auth') || null);
  const [currentUser, setCurrentUser] = useState(null);
  const [authLoading, setAuthLoading] = useState(true);

  useEffect(() => {
    if (!authToken) { setAuthLoading(false); return; }
    fetch('/api/auth/me', { headers: { Authorization: 'Bearer ' + authToken } })
      .then(r => r.ok ? r.json() : null)
      .then(user => {
        if (user) setCurrentUser(user);
        else { setAuthToken(null); localStorage.removeItem('jv_auth'); }
        setAuthLoading(false);
      })
      .catch(() => setAuthLoading(false));
  }, []);

  const handleAuth = (token, user) => {
    localStorage.setItem('jv_auth', token);
    setAuthToken(token); setCurrentUser(user);
  };
  const logout = () => {
    localStorage.removeItem('jv_auth');
    setAuthToken(null); setCurrentUser(null); setVotedSongs(new Set());
    cancelAnimationFrame(crossfadeRaf.current);
    [audioA.current, audioB.current].forEach(a => { if (a) { a.pause(); a.src = ''; a.volume = 1; } });
  };
  const isAdmin = currentUser?.role === 'admin';

  const authFetch = (url, opts = {}) => fetch(url, {
    ...opts,
    headers: { 'Content-Type': 'application/json', ...opts.headers, Authorization: 'Bearer ' + authToken }
  });

  // ── dual audio + crossfade ─────────────────────────────────────────────────
  const audioA        = useRef(null);
  const audioB        = useRef(null);
  const activeRef     = useRef('A');          // which element is the current player
  const fadeScheduled = useRef(false);        // crossfade has been triggered
  const crossfadeRaf  = useRef(null);         // requestAnimationFrame handle

  const getActive   = () => activeRef.current === 'A' ? audioA.current : audioB.current;
  const getInactive = () => activeRef.current === 'A' ? audioB.current : audioA.current;

  // ── player display state ───────────────────────────────────────────────────
  const [nowPlaying, setNowPlaying]   = useState(null);
  const [isPlaying, setIsPlaying]     = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration]       = useState(0);

  // ── queue / voting ─────────────────────────────────────────────────────────
  const [queue, setQueue]           = useState([]);
  const [votedSongs, setVotedSongs] = useState(new Set());
  const [addedSongs, setAddedSongs] = useState(new Set());

  // ── search ─────────────────────────────────────────────────────────────────
  const [q, setQ]                     = useState('');
  const [results, setResults]         = useState([]);
  const [searching, setSearching]     = useState(false);
  const [showResults, setShowResults] = useState(false);
  const searchTimer = useRef(null);
  const searchRef   = useRef(null);

  // ── library ────────────────────────────────────────────────────────────────
  const [libraryOpen, setLibraryOpen]           = useState(false);
  const [playlists, setPlaylists]               = useState([]);
  const [selectedPlaylist, setSelectedPlaylist] = useState(null);
  const [browseSongs, setBrowseSongs]           = useState([]);
  const [browseLoading, setBrowseLoading]       = useState(false);

  // ── toast ──────────────────────────────────────────────────────────────────
  const [toast, setToast] = useState(null);
  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 3000); };

  // ── DJ session ─────────────────────────────────────────────────────────────
  const [sessionActive, setSessionActive]     = useState(null);
  const [sessionName, setSessionName]         = useState('');
  const [sessionDesc, setSessionDesc]         = useState('');
  const [sessionPanelOpen, setSessionPanelOpen] = useState(false);
  const [voterListening, setVoterListening] = useState(false);

  // ── init after auth ────────────────────────────────────────────────────────
  useEffect(() => {
    if (!authToken || !currentUser) return;
    socket.on('queue:update',   (q) => setQueue(q));
    socket.on('session:update', ({ active, name, desc }) => {
      setSessionActive(active);
      if (name !== undefined) setSessionName(name || '');
      if (desc  !== undefined) setSessionDesc(desc  || '');
    });
    socket.on('player:update', (song) => {
      setNowPlaying(song);
      if (!song) {
        cancelAnimationFrame(crossfadeRaf.current);
        fadeScheduled.current = false;
        [audioA.current, audioB.current].forEach(a => { if (a) { a.pause(); a.src = ''; a.volume = 1; } });
        activeRef.current = 'A';
        setIsPlaying(false); setCurrentTime(0); setDuration(0);
        setVoterListening(false);
      } else if (currentUser?.role !== 'admin') {
        // voter: reconnect to live broadcast on song change
        setVoterListeningSong(song);
      }
    });
    socket.on('player:progress', (data) => {
      if (data && !getActive()?.src) {
        setCurrentTime(data.position || 0); setDuration(data.duration || 0);
      }
    });
    fetch('/api/session/status').then(r => r.json()).then(({ active, name, desc }) => {
      setSessionActive(active); setSessionName(name || ''); setSessionDesc(desc || '');
    }).catch(() => setSessionActive(false));
    fetch('/api/now-playing').then(r => r.json()).then(song => {
      setNowPlaying(song);
      if (song && audioA.current) { activeRef.current = 'A'; audioA.current.src = '/api/stream/' + song.id; }
    });
    authFetch('/api/queue').then(r => r.json()).then(setQueue);
    authFetch('/api/playlists').then(r => r.json()).then(setPlaylists).catch(() => {});
    authFetch('/api/queue/my-votes').then(r => r.json())
      .then(ids => setVotedSongs(new Set(ids))).catch(() => {});
    return () => { socket.off('queue:update'); socket.off('player:update'); socket.off('player:progress'); socket.off('session:update'); };
  }, [authToken, currentUser]);

  useEffect(() => {
    const h = (e) => { if (searchRef.current && !searchRef.current.contains(e.target)) setShowResults(false); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);

  // ── audio: load & play on active element ──────────────────────────────────
  const loadAndPlay = (song) => {
    cancelAnimationFrame(crossfadeRaf.current);
    fadeScheduled.current = false;
    [audioA.current, audioB.current].forEach(a => { if (a) { a.pause(); a.src = ''; a.volume = 1; } });
    activeRef.current = 'A';
    if (!audioA.current || !song) return;
    audioA.current.src = '/api/stream/' + song.id;
    audioA.current.load();
    audioA.current.play().then(() => setIsPlaying(true)).catch(() => setIsPlaying(false));
  };

  // voter: switch to new song if listening (called from player:update)
  const setVoterListeningSong = (song) => {
    if (!audioA.current || !song || !voterListening) return;
    // Reconnect to broadcast — server has already switched the stream
    audioA.current.src = '/api/live?t=' + Date.now();
    audioA.current.load();
    audioA.current.play().catch(() => {});
  };

  const startListening = async () => {
    try {
      if (!audioA.current) return;
      audioA.current.src = '/api/live';
      audioA.current.volume = 1;
      audioA.current.load();
      await audioA.current.play();
      setVoterListening(true);
    } catch (e) { console.warn('listen failed', e); }
  };

  const stopListening = () => {
    if (audioA.current) { audioA.current.pause(); audioA.current.src = ''; }
    setVoterListening(false);
  };

  // crossfade: immediately start incoming audio at vol 0, ramp both over 4 s
  // Synchronous so RAF begins before any network delay
  const triggerCrossfade = (nextQueue) => {
    if (!nextQueue || nextQueue.length === 0) { fadeScheduled.current = false; return; }
    const nextSong = nextQueue[0]; // use queue already in state

    const out = getActive();
    const inn = getInactive();
    if (!out || !inn) { fadeScheduled.current = false; return; }

    // Load and start incoming at volume 0 immediately
    inn.volume = 0;
    inn.src = '/api/stream/' + nextSong.id;
    inn.load();
    inn.play().catch(() => {});

    // Advance queue on server (fire-and-forget, no await)
    authFetch('/api/player/next', { method: 'POST' })
      .then(r => r.json())
      .then(({ song }) => { if (song) setNowPlaying(song); })
      .catch(() => {});

    const startVol = out.volume > 0 ? out.volume : 1;
    const t0 = performance.now();
    cancelAnimationFrame(crossfadeRaf.current);

    const tick = (now) => {
      const p = Math.min((now - t0) / 4000, 1);
      if (out) out.volume = startVol * (1 - p);
      if (inn) inn.volume = p;
      if (p < 1) {
        crossfadeRaf.current = requestAnimationFrame(tick);
      } else {
        if (out) { out.pause(); out.src = ''; out.volume = 1; }
        activeRef.current = activeRef.current === 'A' ? 'B' : 'A';
        fadeScheduled.current = false;
      }
    };
    crossfadeRaf.current = requestAnimationFrame(tick);
  };

  // ── audio event handlers ───────────────────────────────────────────────────
  const handleTimeUpdate = (which) => {
    if (which !== activeRef.current) return;
    const audio = getActive();
    if (!audio) return;
    const ct  = audio.currentTime;
    const dur = audio.duration || 0;
    setCurrentTime(ct);
    setDuration(dur);
    socket.emit('player:progress', { position: ct, duration: dur });
    // Trigger crossfade 4 s before end (admin only, queue must have next song)
    if (isAdmin && dur > 4 && dur - ct <= 4 && !fadeScheduled.current && queue.length > 0) {
      fadeScheduled.current = true;
      triggerCrossfade(queue);
    }
  };

  const handleEnded = async (which) => {
    if (which !== activeRef.current) return;
    if (fadeScheduled.current) {
      // Crossfade was triggered but animation may still be running — force complete
      cancelAnimationFrame(crossfadeRaf.current);
      const out = getActive(); const inn = getInactive();
      if (out) { out.pause(); out.src = ''; out.volume = 1; }
      if (inn) inn.volume = 1;
      activeRef.current = activeRef.current === 'A' ? 'B' : 'A';
      fadeScheduled.current = false;
      setIsPlaying(true);
      return;
    }
    // Normal end — no crossfade (queue was empty at -4s mark)
    setIsPlaying(false);
    const r = await authFetch('/api/player/next', { method: 'POST' });
    const { song } = await r.json();
    if (song) loadAndPlay(song);
  };

  const togglePlay = () => {
    const audio = getActive();
    if (!audio || !nowPlaying) return;
    if (isPlaying) { audio.pause(); setIsPlaying(false); }
    else { audio.play().then(() => setIsPlaying(true)).catch(() => {}); }
  };

  const handleSkip = async () => {
    cancelAnimationFrame(crossfadeRaf.current);
    fadeScheduled.current = false;
    [audioA.current, audioB.current].forEach(a => { if (a) { a.pause(); a.src = ''; a.volume = 1; } });
    activeRef.current = 'A';
    setIsPlaying(false);
    const r = await authFetch('/api/player/next', { method: 'POST' });
    const { song } = await r.json();
    if (song) loadAndPlay(song);
  };

  const handleStart = async () => {
    const r = await authFetch('/api/player/next', { method: 'POST' });
    const { song } = await r.json();
    if (song) loadAndPlay(song);
  };

  const seekTo = (e) => {
    const audio = getActive();
    if (!audio || !duration) return;
    const rect = e.currentTarget.getBoundingClientRect();
    audio.currentTime = ((e.clientX - rect.left) / rect.width) * duration;
  };

  const pct = duration > 0 ? Math.min(100, (currentTime / duration) * 100) : 0;

  // ── search ─────────────────────────────────────────────────────────────────
  const doSearch = (val) => {
    clearTimeout(searchTimer.current);
    if (val.length < 2) { setResults([]); setShowResults(false); return; }
    searchTimer.current = setTimeout(async () => {
      setSearching(true);
      try {
        const r = await authFetch('/api/search?q=' + encodeURIComponent(val));
        const data = await r.json(); setResults(data); setShowResults(true);
      } catch { setResults([]); }
      setSearching(false);
    }, 350);
  };

  // ── library browse ─────────────────────────────────────────────────────────
  const loadBrowse = async (playlistId) => {
    setSelectedPlaylist(playlistId); setBrowseLoading(true);
    try {
      const url = playlistId ? '/api/browse?playlist=' + encodeURIComponent(playlistId) : '/api/browse';
      setBrowseSongs(await (await authFetch(url)).json());
    } catch { setBrowseSongs([]); }
    setBrowseLoading(false);
  };
  const toggleLibrary = () => {
    const next = !libraryOpen; setLibraryOpen(next);
    if (next && browseSongs.length === 0) loadBrowse(null);
  };

  // ── add / vote / delete ────────────────────────────────────────────────────
  const handleAddSong = async (song) => {
    setAddedSongs(prev => new Set([...prev, song.id]));
    const r = await authFetch('/api/queue/add', { method: 'POST', body: JSON.stringify({ song }) });
    if (!r.ok) {
      setAddedSongs(prev => { const n = new Set(prev); n.delete(song.id); return n; });
      const data = await r.json().catch(() => ({}));
      showToast(data.error || 'Error al anadir cancion');
    }
  };

  const handleVote = async (songId) => {
    if (votedSongs.has(songId)) { showToast('Ya has votado esta cancion'); return; }
    const now = new Date().toISOString();
    setVotedSongs(prev => { const n = new Set(prev); n.add(songId); return n; });
    setQueue(prev =>
      [...prev.map(s => s.id === songId ? { ...s, votes: s.votes + 1, first_voted_at: s.first_voted_at || now } : s)]
        .sort((a, b) => {
          if (b.votes !== a.votes) return b.votes - a.votes;
          const fa = a.first_voted_at ? new Date(a.first_voted_at).getTime() : Infinity;
          const fb = b.first_voted_at ? new Date(b.first_voted_at).getTime() : Infinity;
          if (fa !== fb) return fa - fb;
          return new Date(a.added_at) - new Date(b.added_at);
        })
    );
    await authFetch('/api/queue/vote', { method: 'POST', body: JSON.stringify({ songId }) });
  };

  const handleDelete = async (songId) => {
    await authFetch('/api/queue/' + songId, { method: 'DELETE', headers: {} });
  };

  const stopAudio = () => {
    cancelAnimationFrame(crossfadeRaf.current);
    fadeScheduled.current = false;
    [audioA.current, audioB.current].forEach(a => { if (a) { a.pause(); a.src = ''; a.volume = 1; } });
    activeRef.current = 'A'; setIsPlaying(false);
  };


  // ── Media Session API: lock-screen controls + background playback ──────────
  useEffect(() => {
    if (!('mediaSession' in navigator)) return;
    if (!nowPlaying) { navigator.mediaSession.metadata = null; return; }
    navigator.mediaSession.metadata = new MediaMetadata({
      title:  nowPlaying.title  || 'Desconocido',
      artist: nowPlaying.artist || '',
      album:  nowPlaying.album  || '',
      artwork: nowPlaying.cover_art_id
        ? [{ src: '/api/cover/' + nowPlaying.cover_art_id, sizes: '512x512', type: 'image/jpeg' }]
        : []
    });
    const audio = audioA.current;
    navigator.mediaSession.setActionHandler('play',  () => { if (audio) audio.play().then(() => setIsPlaying(true)).catch(() => {}); });
    navigator.mediaSession.setActionHandler('pause', () => { if (audio) { audio.pause(); if (!voterListening) setIsPlaying(false); } });
    navigator.mediaSession.setActionHandler('stop',  () => { if (audio) { audio.pause(); audio.src = ''; } setIsPlaying(false); setVoterListening(false); });
    navigator.mediaSession.setActionHandler('nexttrack', isAdmin ? handleSkip : null);
  }, [nowPlaying, isAdmin]);
  // ── render ─────────────────────────────────────────────────────────────────
  if (authLoading || (currentUser && sessionActive === null)) return (
    <div className="min-h-[100dvh] flex items-center justify-center" style={{ background: '#0d0608' }}>
      <div className="w-8 h-8 border-2 border-red-700 border-t-transparent rounded-full animate-spin" />
    </div>
  );
  if (!currentUser) return <AuthModal onAuth={handleAuth} />;

  // Non-admin waiting screen when session is closed
  if (!isAdmin && !sessionActive) return (
    <div className="min-h-[100dvh] flex flex-col items-center justify-center fade-in px-6"
      style={{ background: 'linear-gradient(160deg, #1a0505 0%, #0d0608 100%)' }}>
      <img src={LOGO} className="w-28 h-28 object-contain rounded-full bg-white/5 p-3 mb-8" alt="" />
      <h1 className="text-3xl font-extrabold text-white mb-1 tracking-tight">
        {sessionName || 'TuriaDJ'}
      </h1>
      <p className="text-[11px] text-red-400 font-semibold uppercase tracking-widest leading-tight">Falla Turia · Plaça de l'Ajuntament</p>
      {sessionDesc && (
        <p className="text-gray-500 text-sm text-center max-w-xs mt-4 leading-relaxed">{sessionDesc}</p>
      )}
      <div className="flex items-center gap-3 bg-gray-900/60 border border-gray-800/50 rounded-2xl px-6 py-4 mt-8">
        <div className="w-2.5 h-2.5 rounded-full bg-yellow-600/70 animate-pulse flex-shrink-0" />
        <div>
          <p className="text-gray-300 text-sm font-semibold">Sesion no iniciada</p>
          <p className="text-gray-600 text-xs mt-0.5">El DJ abrira la sesion en breve...</p>
        </div>
      </div>
      <button onClick={logout} className="mt-10 text-xs text-gray-700 hover:text-gray-500 transition-colors flex items-center gap-1.5">
        <LogOut size={12} /> Cerrar sesion
      </button>
    </div>
  );

  return (
    <div className="min-h-[100dvh] text-white flex flex-col max-w-2xl mx-auto px-4 pb-10"
      style={{ background: 'linear-gradient(160deg, #1a0505 0%, #0d0608 40%, #0d0608 100%)' }}>

      {adminPanelOpen && (
        <AdminPanel currentUser={currentUser} authToken={authToken} onClose={() => setAdminPanelOpen(false)} />
      )}

      {sessionPanelOpen && (
        <SessionPanel
          sessionActive={sessionActive}
          sessionName={sessionName}
          sessionDesc={sessionDesc}
          authFetch={authFetch}
          onStopAudio={stopAudio}
          onClose={() => setSessionPanelOpen(false)}
        />
      )}

      {toast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 fade-in">
          <div className="bg-gray-800 border border-gray-700 text-white text-sm px-5 py-3 rounded-2xl shadow-xl whitespace-nowrap">{toast}</div>
        </div>
      )}

      {/* Header */}
      <div className="relative z-10 flex items-center gap-3 py-4">
        <img src={LOGO} className="w-10 h-10 object-contain rounded-full bg-white p-0.5" alt="Falla" />
        <div className="flex-1 min-w-0">
          <p className="font-extrabold text-base leading-tight tracking-tight">TuriaDJ</p>
          {sessionName ? (
            <>
              <p className="text-[11px] text-yellow-500 font-semibold leading-tight truncate">{sessionName}</p>
              {sessionDesc && (
                <p className="text-[10px] text-gray-500 leading-tight truncate mt-0.5">{sessionDesc}</p>
              )}
            </>
          ) : (
            <p className="text-[10px] text-red-400 font-semibold uppercase tracking-widest leading-tight">
              Falla Turia · Plaça de l'Ajuntament
            </p>
          )}
        </div>
        <div className="ml-auto flex items-center gap-3">
          <div className="flex items-center gap-1.5">
            <div className={'w-2 h-2 rounded-full ' + (isAdmin ? (sessionActive ? 'bg-green-500' : 'bg-gray-600') : (sessionActive ? 'bg-green-500 animate-pulse' : 'bg-gray-600'))} />
            <span className="text-xs text-gray-500">{currentUser.username}</span>
            {isAdmin && <span className="text-[10px] bg-yellow-900/50 text-yellow-500 px-1.5 py-0.5 rounded font-semibold">ADMIN</span>}
          </div>
          {isAdmin && (
            <button onClick={() => setAdminPanelOpen(true)}
              className="text-gray-600 hover:text-yellow-500 transition-colors" title="Panel de control">
              <Settings size={16} />
            </button>
          )}
          {isAdmin && (
            <button onClick={() => setSessionPanelOpen(true)}
              className={'transition-colors ' + (sessionActive ? 'text-green-500 hover:text-green-400' : 'text-gray-600 hover:text-yellow-500')}
              title="Editar sesion">
              <Edit2 size={15} />
            </button>
          )}
          <button onClick={logout} className="text-gray-600 hover:text-gray-400 transition-colors">
            <LogOut size={16} />
          </button>
        </div>
      </div>

      {/* Player */}
      <div className="relative z-10 rounded-2xl p-4 mb-5 border border-red-900/40 overflow-hidden"
        style={{ background: 'linear-gradient(135deg, rgba(127,29,29,0.35) 0%, rgba(30,5,5,0.95) 100%)' }}>
        <div className="absolute right-2 top-2 opacity-[0.07] pointer-events-none">
          <img src={LOGO} className="w-28 h-28 object-contain" alt="" />
        </div>
        {nowPlaying ? (
          <>
            <div className="flex items-center gap-4 mb-4">
              <CoverImg id={nowPlaying.cover_art_id} size="lg" />
              <div className="flex-1 min-w-0">
                <p className="text-[10px] text-red-400 font-semibold uppercase tracking-widest mb-1">Sonando ahora</p>
                <p className="font-bold text-base truncate">{nowPlaying.title}</p>
                <p className="text-gray-400 text-sm truncate">{nowPlaying.artist}</p>
                {nowPlaying.album && nowPlaying.album !== '[Unknown Album]' &&
                  <p className="text-gray-600 text-xs truncate">{nowPlaying.album}</p>}
              </div>
            </div>
            <div className={'mb-3 ' + (isAdmin ? 'cursor-pointer' : '')} onClick={isAdmin ? seekTo : undefined}>
              <div className="h-1.5 bg-gray-800 rounded-full overflow-hidden">
                <div className="h-full rounded-full transition-all duration-300"
                  style={{ width: pct + '%', background: 'linear-gradient(90deg, #dc2626, #f59e0b)' }} />
              </div>
              <div className="flex justify-between text-xs text-gray-600 mt-1">
                <span>{fmtDur(currentTime)}</span>
                <span>{fmtDur(duration || nowPlaying.duration)}</span>
              </div>
            </div>
            {!isAdmin && (
              <div className="flex items-center gap-3 mt-1">
                <button onClick={voterListening ? stopListening : startListening}
                  className={'flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold transition-all active:scale-95 ' +
                    (voterListening
                      ? 'bg-gray-700 text-gray-300 hover:bg-gray-600'
                      : 'text-white hover:opacity-90')}
                  style={voterListening ? {} : { background: 'linear-gradient(135deg, #dc2626, #b91c1c)' }}>
                  {voterListening
                    ? <><VolumeX size={15} /><span>Silenciar</span></>
                    : <><Volume2 size={15} /><span>Escuchar</span></>}
                </button>
                {voterListening && (
                  <span className="text-xs text-green-400 flex items-center gap-1">
                    <span className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse inline-block" />
                    En directo
                  </span>
                )}
              </div>
            )}
            {isAdmin && (
              <div className="flex items-center gap-3">
                <button onClick={togglePlay}
                  className="w-12 h-12 rounded-2xl flex items-center justify-center transition-all active:scale-95 shadow-lg"
                  style={{ background: 'linear-gradient(135deg, #dc2626, #b91c1c)', boxShadow: '0 4px 20px rgba(220,38,38,0.4)' }}>
                  {isPlaying ? <Pause size={20} className="text-white" /> : <Play size={20} className="text-white ml-0.5" />}
                </button>
                <button onClick={handleSkip}
                  className="w-10 h-10 bg-gray-800/80 hover:bg-gray-700 rounded-xl flex items-center justify-center transition-all active:scale-95 text-gray-400 hover:text-white">
                  <SkipForward size={18} />
                </button>
                {queue.length > 0 && (
                  <p className="ml-auto text-xs text-gray-600 truncate max-w-[140px]">
                    Siguiente: <span className="text-gray-400">{queue[0].title}</span>
                  </p>
                )}
              </div>
            )}
          </>
        ) : (
          <div className="flex items-center gap-4 py-2">
            <div className="w-20 h-20 bg-gray-800/50 rounded-xl flex items-center justify-center flex-shrink-0">
              <Music size={28} className="text-gray-600" />
            </div>
            <div>
              <p className="font-semibold text-gray-400">Sin reproducir</p>
              <p className="text-sm text-gray-600 mt-1">Busca una cancion y añadela a la cola</p>
              {isAdmin && queue.length > 0 && (
                <button onClick={handleStart}
                  className="mt-2 flex items-center gap-1.5 text-xs text-red-400 hover:text-red-300 transition-colors">
                  <Play size={12} /> Empezar
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Search */}
      <div ref={searchRef} className="relative z-20 mb-4">
        <p className="text-xs text-gray-600 font-semibold uppercase tracking-widest mb-2">Buscar canciones</p>
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 z-10" />
          <input value={q}
            onChange={e => { setQ(e.target.value); doSearch(e.target.value); }}
            onFocus={() => { if (results.length > 0) setShowResults(true); }}
            placeholder="Busca canciones, artistas, albums..."
            className="w-full bg-gray-900/80 border border-gray-700/50 focus:border-red-600/60 rounded-xl pl-9 pr-10 py-3 text-sm focus:outline-none placeholder-gray-600 transition-colors" />
          {q && (
            <button onClick={() => { setQ(''); setResults([]); setShowResults(false); }}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-white">
              <X size={16} />
            </button>
          )}
        </div>
        {showResults && (
          <div className="absolute top-full left-0 right-0 mt-1 bg-gray-900 border border-gray-700/50 rounded-xl shadow-2xl z-50 overflow-hidden">
            <div className="max-h-72 overflow-y-auto rounded-xl">
              {searching && <div className="flex justify-center py-6"><div className="w-5 h-5 border-2 border-red-600 border-t-transparent rounded-full animate-spin" /></div>}
              {!searching && results.length === 0 && <p className="text-center py-6 text-gray-500 text-sm">Sin resultados</p>}
              {!searching && results.map(song => (
                <button key={song.id}
                  onClick={() => { handleAddSong(song); setQ(''); setShowResults(false); setResults([]); }}
                  disabled={addedSongs.has(song.id) || !!queue.find(s => s.id === song.id)}
                  className={'w-full flex items-center gap-3 px-4 py-3 hover:bg-gray-800 transition-colors text-left border-b border-gray-800/40 last:border-0 ' +
                    (addedSongs.has(song.id) || queue.find(s => s.id === song.id) ? 'opacity-40 cursor-default' : 'cursor-pointer')}>
                  <CoverImg id={song.coverArt} size="sm" />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate">{song.title}</p>
                    <p className="text-xs text-gray-400 truncate">{song.artist}{song.album ? ' · ' + song.album : ''}</p>
                  </div>
                  {addedSongs.has(song.id) || queue.find(s => s.id === song.id)
                    ? <span className="text-xs text-gray-500 flex-shrink-0">En cola</span>
                    : <Plus size={16} className="text-red-400 flex-shrink-0" />}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Library */}
      <div className="relative z-10 mb-5">
        <button onClick={toggleLibrary} className="flex items-center gap-2 w-full text-left mb-3 group">
          <p className="text-xs text-gray-600 font-semibold uppercase tracking-widest group-hover:text-gray-400 transition-colors">Biblioteca</p>
          <ChevronDown size={13} className={'text-gray-600 group-hover:text-gray-400 transition-all ' + (libraryOpen ? 'rotate-180' : '')} />
        </button>
        {libraryOpen && (
          <div className="fade-in">
            <div className="flex flex-wrap gap-2 pb-2 mb-3">
              <button onClick={() => loadBrowse(null)}
                className={'px-3 py-1.5 rounded-full text-xs font-semibold whitespace-nowrap transition-all flex-shrink-0 ' +
                  (selectedPlaylist === null ? 'bg-red-700 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white')}>
                Aleatorio
              </button>
              {playlists.map(pl => (
                <button key={pl.id} onClick={() => loadBrowse(pl.id)}
                  className={'px-3 py-1.5 rounded-full text-xs font-semibold whitespace-nowrap transition-all flex-shrink-0 ' +
                    (selectedPlaylist === pl.id ? 'bg-red-700 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white')}>
                  {pl.name}<span className="ml-1 opacity-40 font-normal">{pl.count}</span>
                </button>
              ))}
            </div>
            <div className="max-h-80 overflow-y-auto space-y-0.5">
              {browseLoading && <div className="flex justify-center py-10"><div className="w-6 h-6 border-2 border-red-600 border-t-transparent rounded-full animate-spin" /></div>}
              {!browseLoading && browseSongs.length === 0 && <p className="text-center py-8 text-gray-600 text-sm">Sin canciones</p>}
              {!browseLoading && browseSongs.map(song => {
                const inQueue = !!queue.find(s => s.id === song.id);
                const added   = addedSongs.has(song.id);
                return (
                  <button key={song.id} onClick={() => { if (!inQueue && !added) handleAddSong(song); }}
                    disabled={inQueue || added}
                    className={'w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-colors text-left group/item ' +
                      (inQueue || added ? 'opacity-40 cursor-default' : 'hover:bg-gray-800/60 cursor-pointer')}>
                    <CoverImg id={song.coverArt} size="sm" />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium truncate">{song.title}</p>
                      <p className="text-xs text-gray-500 truncate">{song.artist}{song.album ? ' · ' + song.album : ''}</p>
                    </div>
                    <div className="flex-shrink-0">
                      {inQueue || added ? <span className="text-xs text-gray-600">En cola</span>
                        : <Plus size={15} className="text-gray-600 group-hover/item:text-red-400 transition-colors" />}
                    </div>
                  </button>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* Queue */}
      <div className="relative z-10">
        <div className="flex items-center justify-between mb-3">
          <p className="text-xs text-gray-600 font-semibold uppercase tracking-widest">
            Cola {queue.length > 0 && '(' + queue.length + ')'}
          </p>
          {queue.length > 0 && <p className="text-xs text-gray-700">Vota la siguiente cancion</p>}
        </div>
        {queue.length === 0 && (
          <div className="text-center py-10 border border-dashed border-red-900/30 rounded-2xl">
            <img src={LOGO} className="w-14 h-14 object-contain mx-auto mb-3 opacity-20" alt="" />
            <p className="text-gray-500 text-sm font-medium">La cola esta vacia</p>
            <p className="text-gray-700 text-xs mt-1">Busca una cancion arriba para añadirla</p>
          </div>
        )}
        <div className="space-y-2">
          {queue.map((song, i) => {
            const voted = votedSongs.has(song.id);
            return (
              <div key={song.id} className={'flex items-center gap-3 p-3 rounded-xl border transition-all fade-in ' +
                (i === 0 ? 'border-red-800/40 bg-red-950/30' : 'border-gray-800/30 bg-gray-900/40 hover:border-gray-700/40')}>
                <div className="w-6 flex-shrink-0 text-center">
                  {i === 0 ? <span className="text-yellow-500 text-xs font-bold">#1</span>
                           : <span className="text-gray-600 text-xs">#{i + 1}</span>}
                </div>
                <CoverImg id={song.cover_art_id} size="sm" />
                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-sm truncate text-gray-100">{song.title}</p>
                  <p className="text-gray-400 text-xs truncate">
                    {song.artist}{song.album && song.album !== '[Unknown Album]' ? ' · ' + song.album : ''}
                  </p>
                </div>
                <button onClick={() => handleVote(song.id)}
                  className={'flex flex-col items-center gap-0.5 px-3 py-2 rounded-xl transition-all select-none flex-shrink-0 ' +
                    (voted ? 'bg-red-900/30 text-red-400 cursor-default'
                           : 'bg-gray-800/80 hover:bg-red-900/30 hover:text-red-400 text-gray-500 active:scale-95 cursor-pointer')}>
                  <ThumbsUp size={16} fill={voted ? 'currentColor' : 'none'} />
                  <span className="text-xs font-bold leading-none">{song.votes}</span>
                </button>
                {isAdmin && (
                  <button onClick={() => handleDelete(song.id)}
                    className="flex-shrink-0 w-8 h-8 flex items-center justify-center text-gray-700 hover:text-red-500 hover:bg-red-900/20 rounded-lg transition-all">
                    <Trash2 size={14} />
                  </button>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Two audio elements for crossfade */}
      <audio ref={audioA} playsInline
        onEnded={() => handleEnded('A')}
        onTimeUpdate={() => handleTimeUpdate('A')}
        onPlay={() => { if (activeRef.current === 'A') setIsPlaying(true); }}
        onPause={() => { if (activeRef.current === 'A' && !fadeScheduled.current) setIsPlaying(false); }}
        onLoadedMetadata={() => { if (activeRef.current === 'A') setDuration(audioA.current?.duration || 0); }}
      />
      <audio ref={audioB} playsInline
        onEnded={() => handleEnded('B')}
        onTimeUpdate={() => handleTimeUpdate('B')}
        onPlay={() => {}}
        onPause={() => {}}
        onLoadedMetadata={() => { if (activeRef.current === 'B') setDuration(audioB.current?.duration || 0); }}
      />
    </div>
  );
}
